   129→
   130→  /** The name attribute, present for all rules at index 0. Also defined for all symbolic macros. */
   131→  public static final Attribute NAME_ATTRIBUTE =
   132→      attr("name", STRING_NO_INTERN)
   133→          .nonconfigurable("All rules have a non-customizable \"name\" attribute")
   134→          .mandatory()
   135→          .build();
   136→
   137→  /**
   138→   * Maximum attributes per RuleClass. Current value was chosen to be high enough to be considered a
   139→   * non-breaking change for reasonable use. It was also chosen to be low enough to give significant
   140→   * headroom before hitting limits imposed by the compact attribute value storage strategy in
   141→   * {@link Rule}.
