    59→      ImmutableList<StarlarkThread.CallStackEntry> callstack)
    60→      throws InvalidRuleException, InterruptedException {
    61→    Preconditions.checkNotNull(ruleClass);
    62→    String ruleClassName = ruleClass.getName();
