    65→      throw new InvalidRuleException(ruleClassName + " rule has no 'name' attribute");
    66→    } else if (!(nameObject instanceof String)) {
    67→      throw new InvalidRuleException(ruleClassName + " 'name' attribute must be a string");
    68→    }
    69→    String name = (String) nameObject;
    70→    Label label;
    71→    try {
    72→      // Test that this would form a valid label name -- in particular, this
    73→      // catches cases where Makefile variables $(foo) appear in "name".
    74→      label = pkgBuilder.createLabel(name);
    75→    } catch (LabelSyntaxException e) {
    76→      throw new InvalidRuleException("illegal rule name: " + name + ": " + e.getMessage());
    77→    }
    78→    boolean inWorkspaceFile = pkgBuilder.isRepoRulePackage();
    79→    if (ruleClass.getWorkspaceOnly() && !inWorkspaceFile) {
    80→      throw new RuleFactory.InvalidRuleException(
    81→          ruleClass + " must be in the WORKSPACE file " + "(used by " + label + ")");
    82→    } else if (!ruleClass.getWorkspaceOnly() && inWorkspaceFile) {
    83→      throw new RuleFactory.InvalidRuleException(
    84→          ruleClass + " cannot be in the WORKSPACE file " + "(used by " + label + ")");
    85→    }
    86→
    87→    // Add the generator_name attribute.
    88→    BuildLangTypedAttributeValuesMap processedAttributes;
    89→    @Nullable String generatorName = getGeneratorName(pkgBuilder, attributeValues, callstack);
    90→    // Don't bother copying anything if nothing changed.
    91→    if (generatorName != null) {
    92→      ImmutableMap.Builder<String, Object> builder =
    93→          ImmutableMap.builderWithExpectedSize(attributeValues.attributeValues.size() + 1);
    94→      builder.putAll(attributeValues.attributeValues);
    95→      builder.put("generator_name", generatorName);
    96→      processedAttributes = new BuildLangTypedAttributeValuesMap(builder.buildKeepingLast());
    97→    } else {
    98→      processedAttributes = attributeValues;
    99→    }
